import { IMessageComposer } from '@nitrots/nitro-renderer';

export class MythicalBlueprintAddItemComposer implements IMessageComposer<any[]>
{
private _data: any[];

constructor(sessionId: number, blueprintItemId: number, inventoryRowId: number, quantity: number, slotIndex: number)
{
// Must match MythicalBlueprintAddItemEvent.java order EXACTLY:
// sessionId, blueprintItemId, inventoryRowId, quantity, slotIndex
this._data = [
sessionId,
blueprintItemId,
inventoryRowId,
quantity,
slotIndex
];

console.log('Packet MythicalBlueprintAddItemComposer sent');
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}